class TrainingDataStore:
    """Manages community-contributed training data."""
    
    def __init__(self, data_folder):
        self.data_folder = data_folder
        self.metadata_file = os.path.join(data_folder, "metadata", "contributions.json")
        self.lock = threading.Lock()
        self._load_metadata()
    
    def _load_metadata(self):
        if os.path.exists(self.metadata_file):
            with open(self.metadata_file, "r") as f:
                self.metadata = json.load(f)
        else:
            self.metadata = {
                "contributions": [],
                "classes": [],
                "total_samples": 0,
                "contributors": {}
            }
    
    def _save_metadata(self):
        with open(self.metadata_file, "w") as f:
            json.dump(self.metadata, f, indent=2, default=str)
    
    def add_contribution(self, contributor_id, image_path, label, confidence=None):
        with self.lock:
            contribution = {
                "id": str(uuid.uuid4()),
                "contributor_id": contributor_id,
                "image_path": image_path,
                "label": label,
                "confidence": confidence,
                "timestamp": datetime.now().isoformat(),
                "verified": False,
                "flagged": False
            }
            self.metadata["contributions"].append(contribution)
            
            if label not in self.metadata["classes"]:
                self.metadata["classes"].append(label)
            
            self.metadata["total_samples"] += 1
            
            if contributor_id not in self.metadata["contributors"]:
                self.metadata["contributors"][contributor_id] = {
                    "total_contributions": 0,
                    "verified_contributions": 0,
                    "first_contribution": datetime.now().isoformat()
                }
            self.metadata["contributors"][contributor_id]["total_contributions"] += 1
            
            self._save_metadata()
            return contribution["id"]
    
    def get_training_data(self, verified_only=False):
        contributions = self.metadata["contributions"]
        if verified_only:
            contributions = [c for c in contributions if c["verified"] and not c["flagged"]]
        else:
            contributions = [c for c in contributions if not c["flagged"]]
        return contributions
    
    def flag_contribution(self, contribution_id, reason=""):
        with self.lock:
            for contrib in self.metadata["contributions"]:
                if contrib["id"] == contribution_id:
                    contrib["flagged"] = True
                    contrib["flag_reason"] = reason
                    self._save_metadata()
                    return True
        return False
    
    def verify_contribution(self, contribution_id):
        with self.lock:
            for contrib in self.metadata["contributions"]:
                if contrib["id"] == contribution_id:
                    contrib["verified"] = True
                    contributor_id = contrib["contributor_id"]
                    if contributor_id in self.metadata["contributors"]:
                        self.metadata["contributors"][contributor_id]["verified_contributions"] += 1
                    self._save_metadata()
                    return True
        return False
    
    def get_stats(self):
        total = len(self.metadata["contributions"])
        verified = sum(1 for c in self.metadata["contributions"] if c["verified"])
        flagged = sum(1 for c in self.metadata["contributions"] if c["flagged"])
        return {
            "total_contributions": total,
            "verified": verified,
            "flagged": flagged,
            "classes": self.metadata["classes"],
            "num_classes": len(self.metadata["classes"]),
            "num_contributors": len(self.metadata["contributors"])
        }


class ImageClassificationPipeline:
    """TensorFlow image classification training pipeline."""
    
    def __init__(self, model_folder, image_size=IMAGE_SIZE):
        self.model_folder = model_folder
        self.image_size = image_size
        self.model = None
        self.class_names = []
        self.training_history = []
        self.is_training = False
        self.lock = threading.Lock()
        self._load_latest_model()
    
    def _load_latest_model(self):
        model_path = os.path.join(self.model_folder, "latest_model")
        class_path = os.path.join(self.model_folder, "class_names.json")
        
        if os.path.exists(model_path) and os.path.exists(class_path):
            try:
                self.model = keras.models.load_model(model_path)
                with open(class_path, "r") as f:
                    self.class_names = json.load(f)
                logger.info(f"Loaded model with {len(self.class_names)} classes")
            except Exception as e:
                logger.error(f"Error loading model: {e}")
                self.model = None
    
    def _build_model(self, num_classes):
        """Build a CNN model for image classification."""
        base_model = keras.applications.MobileNetV2(
            input_shape=(*self.image_size, 3),
            include_top=False,
            weights="imagenet"
        )
        base_model.trainable = False  # Freeze base model initially
        
        model = keras.Sequential([
            base_model,
            layers.GlobalAveragePooling2D(),
            layers.BatchNormalization(),
            layers.Dropout(0.3),
            layers.Dense(256, activation="relu"),
            layers.BatchNormalization(),
            layers.Dropout(0.3),
            layers.Dense(128, activation="relu"),
            layers.Dropout(0.2),
            layers.Dense(num_classes, activation="softmax")
        ])
        
        model.compile(
            optimizer=keras.optimizers.Adam(learning_rate=1e-3),
            loss="sparse_categorical_crossentropy",
            metrics=["accuracy"]
        )
        
        return model
    
    def _preprocess_image(self, image_path):
        """Load and preprocess a single image."""
        try:
            img = Image.open(image_path).convert("RGB")
            img = img.resize(self.image_size)
            img_array = np.array(img, dtype=np.float32)
            img_array = keras.applications.mobilenet_v2.preprocess_input(img_array)
            return img_array
        except Exception as e:
            logger.error(f"Error processing image {image_path}: {e}")
            return None
    
    def _prepare_dataset(self, contributions):
        """Prepare TensorFlow dataset from contributions."""
        images = []
        labels = []
        class_names = sorted(list(set(c["label"] for c in contributions)))
        class_to_idx = {name: idx for idx, name in enumerate(class_names)}
        
        for contrib in contributions:
            img = self._preprocess_image(contrib["image_path"])
            if img is not None:
                images.append(img)
                labels.append(class_to_idx[contrib["label"]])
        
        if not images:
            return None, None, class_names
        
        images = np.array(images)
        labels = np.array(labels)
        
        # Shuffle
        indices = np.random.permutation(len(images))
        images = images[indices]
        labels = labels[indices]
        
        # Split train/validation (80/20)
        split_idx = int(0.8 * len(images))
        
        train_dataset = tf.data.Dataset.from_tensor_slices(
            (images[:split_idx], labels[:split_idx])
        ).shuffle(1000).batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)
        
        val_dataset = tf.data.Dataset.from_tensor_slices(
            (images[split_idx:], labels[split_idx:])
        ).batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)
        
        return train_dataset, val_dataset, class_names
    
    def _prepare_dataset_from_csv(self, csv_path, image_base_dir=None):
        """Prepare dataset from a CSV file with columns: image_path, label."""
        try:
            df = pd.read_csv(csv_path)
            
            if "image_path" not in df.columns or "label" not in df.columns:
                raise ValueError("CSV must contain 'image_path' and 'label' columns")
            
            contributions = []
            for _, row in df.iterrows():
                img_path = row["image_path"]
                if image_base_dir:
                    img_path = os.path.join(image_base_dir, img_path)
                contributions.append({
                    "image_path": img_path,
                    "label": str(row["label"])
                })
            
            return self._prepare_dataset(contributions)
        except Exception as e:
            logger.error(f"Error preparing dataset from CSV: {e}")
            raise
    
    def train(self, contributions, epochs=EPOCHS, fine_tune=False):
        """Train the model on community contributions."""
        with self.lock:
            if self.is_training:
                return {"error": "Training already in progress"}
            self.is_training = True
        
        try:
            logger.info(f"Starting training with {len(contributions)} samples")
            
            train_dataset, val_dataset, class_names = self._prepare_dataset(contributions)
            
            if train_dataset is None:
                return {"error": "No valid training data found"}
            
            num_classes = len(class_names)
            
            if num_classes < 2:
                return {"error": "Need at least 2 classes for classification"}
            
            # Build or rebuild model if class count changed
            if self.model is None or len(self.class_names) != num_classes:
                self.model = self._build_model(num_classes)
                self.class_names = class_names
                logger.info(f"Built new model with {num_classes} classes: {class_names}")
            
            # Fine-tune: unfreeze some layers of the base model
            if fine_tune and len(self.model.layers) > 0:
                base = self.model.layers[0]
                if hasattr(base, 'trainable'):
                    base.trainable = True
                    # Freeze all but last 20 layers
                    for layer in base.layers[:-20]:
                        layer.trainable = False
                    self.model.compile(
                        optimizer=keras.optimizers.Adam(learning_rate=1e-5),
                        loss="sparse_categorical_crossentropy",
                        metrics=["accuracy"]
                    )
            
            # Callbacks
            callbacks = [
                keras.callbacks.EarlyStopping(
                    monitor="val_loss",
                    patience=3,
                    restore_best_weights=True
                ),
                keras.callbacks.ReduceLROnPlateau(
                    monitor="val_loss",
                    factor=0.5,
                    patience=2,
                    min_lr=1e-7
                )
            ]
            
            # Data augmentation layer
            data_augmentation = keras.Sequential([
                layers.RandomFlip("horizontal"),
                layers.RandomRotation(0.1),
                layers.RandomZoom(0.1),
                layers.RandomBrightness(0.1),
                layers.RandomContrast(0.1),
            ])
            
            # Apply augmentation to training data
            augmented_train = train_dataset.map(
                lambda x, y: (data_augmentation(x, training=True), y),
                num_parallel_calls=tf.data.AUTOTUNE
            )
            
            # Train
            history = self.model.fit(
                augmented_train,
                validation_data=val_dataset,
                epochs=epochs,
                callbacks=callbacks,
                verbose=1
            )
            
            # Save model
            model_path = os.path.join(self.model_folder, "latest_model")
            self.model.save(model_path)
            
            class_path = os.path.join(self.model_folder, "class_names.json")
            with open(class_path, "w") as f:
                json.dump(self.class_names, f)
            
            # Save versioned copy
            version = datetime.now().strftime("%Y%m%d_%H%M%S")
            versioned_path = os.path.join(self.model_folder, f"model_{version}")
            self.model.save(versioned_path)
            
            # Record training history
            train_result = {
                "version": version,
                "epochs_trained": len(history.history["loss"]),
                "final_loss": float(history.history["loss"][-1]),
                "final_accuracy": float(history.history["accuracy"][-1]),
                "final_val_loss": float(history.history["val_loss"][-1]) if "val_loss" in history.history else None,
                "final_val_accuracy": float(history.history["val_accuracy"][-1]) if "val_accuracy" in history.history else None,
                "num_classes": num_classes,
                "class_names": class_names,
                "num_samples": len(contributions),
                "timestamp": datetime.now().isoformat()
            }
            
            self.training_history.append(train_result)
            
            # Save training history
            history_path = os.path.join(self.model_folder, "training_history.json")
            with open(history_path, "w") as f:
                json.dump(self.training_history, f, indent=2)
            
            logger.info(f"Training complete: {train_result}")
            return train_result
            
        except Exception as e:
            logger.error(f"Training error: {e}")
            return {"error": str(e)}
        finally:
            with self.lock:
                self.is_training = False
    
    def predict(self, image_path):
        """Predict class for a single image."""
        if self.model is None:
            return {"error": "No trained model available"}
        
        img = self._preprocess_image(image_path)
        if img is None:
            return {"error": "Could not process image"}
        
        img_batch = np.expand_dims(img, axis=0)
        predictions = self.model.predict(img_batch, verbose=0)[0]
        
        results = []
        for idx, prob in enumerate(predictions):
            results.append({
                "class": self.class_names[idx],
                "confidence": float(prob)
            })
        
        results.sort(key=lambda x: x["confidence"], reverse=True)
        
        return {
            "predictions": results,
            "top_class": results[0]["class"],
            "top_confidence": results[0]["confidence"]
        }
    
    def get_model_info(self):
        """Get information about the current model."""
        if self.model is None:
            return {"status": "no_model", "message": "No model has been trained yet"}
        
        return {
            "status": "ready",
            "num_classes": len(self.class_names),
            "class_names": self.class_names,
            "model_params": self.model.count_params(),
            "training_history": self.training_history[-5:] if self.training_history else [],
            "is_training": self.is_training
        }


# Initialize global objects
data_store = TrainingDataStore(DATA_FOLDER)
pipeline = ImageClassificationPipeline(MODEL_FOLDER)


def allowed_file(filename, allowed_extensions):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in allowed_extensions


def sanitize_label(label):
    """Sanitize a label string."""
    label = str(label).strip()
    # Only allow alphanumeric, spaces, hyphens, underscores
    sanitized = "".join(c for c in label if c.isalnum() or c in " -_")
    return sanitized[:100]  # Max length


def validate_contributor_id(contributor_id):
    """Validate contributor ID format."""
    if not contributor_id:
        return None
    sanitized = "".join(c for c in str(contributor_id) if c.isalnum() or c in "-_")
    return sanitized[:64] if sanitized else None


