@app.route("/api/contribute/image", methods=["POST"])
def contribute_image():
    """Upload a labeled image to contribute to training data."""
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    file = request.files["image"]
    label = request.form.get("label", "").strip()
    contributor_id = validate_contributor_id(request.form.get("contributor_id", "anonymous"))
    
    if not label:
        return jsonify({"error": "Label is required"}), 400
    
    label = sanitize_label(label)
    if not label:
        return jsonify({"error": "Invalid label"}), 400
    
    if file.filename == "":
        return jsonify({"error": "No file selected"}), 400
    
    if not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": f"Allowed file types: {ALLOWED_IMAGE_EXTENSIONS}"}), 400
    
    # Validate it's actually an image
    try:
        img = Image.open(file.stream)
        img.verify()
        file.stream.seek(0)
    except Exception:
        return jsonify({"error": "Invalid image file"}), 400
    
    # Save the image
    filename = f"{uuid.uuid4()}_{secure_filename(file.filename)}"
    label_dir = os.path.join(DATA_FOLDER, "images", secure_filename(label))
    os.makedirs(label_dir, exist_ok=True)
    filepath = os.path.join(label_dir, filename)
    file.save(filepath)
    
    # Register contribution
    contribution_id = data_store.add_contribution(
        contributor_id=contributor_id,
        image_path=filepath,
        label=label
    )
    
    return jsonify({
        "message": "Image contributed successfully",
        "contribution_id": contribution_id,
        "label": label,
        "contributor_id": contributor_id
    }), 201


@app.route("/api/contribute/batch", methods=["POST"])
def contribute_batch():
    """Upload multiple labeled images at once."""
    if "images" not in request.files:
        return jsonify({"error": "No image files provided"}), 400
    
    labels_json = request.form.get("labels", "")
    contributor_id = validate_contributor_id(request.form.get("contributor_id", "anonymous"))
    
    try:
        labels = json.loads(labels_json) if labels_json else {}
    except json.JSONDecodeError:
        return jsonify({"error": "Invalid labels JSON"}), 400
    
    files = request.files.getlist("images")
    results = []
    
    for file in files:
        if file.filename == "" or not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
            results.append({"filename": file.filename, "status": "skipped", "reason": "invalid file"})
            continue
        
        label = labels.get(file.filename, request.form.get("default_label", ""))
        label = sanitize_label(label)
        
        if not label:
            results.append({"filename": file.filename, "status": "skipped", "reason": "no label"})
            continue
        
        # Validate image
        try:
            img = Image.open(file.stream)
            img.verify()
            file.stream.seek(0)
        except Exception:
            results.append({"filename": file.filename, "status": "skipped", "reason": "invalid image"})
            continue
        
        filename = f"{uuid.uuid4()}_{secure_filename(file.filename)}"
        label_dir = os.path.join(DATA_FOLDER, "images", secure_filename(label))
        os.makedirs(label_dir, exist_ok=True)
        filepath = os.path.join(label_dir, filename)
        file.save(filepath)
        
        contribution_id = data_store.add_contribution(
            contributor_id=contributor_id,
            image_path=filepath,
            label=label
        )
        
        results.append({
            "filename": file.filename,
            "status": "success",
            "contribution_id": contribution_id,
            "label": label
        })
    
    successful = sum(1 for r in results if r["status"] == "success")
    return jsonify({
        "message": f"Processed {len(files)} files, {successful} successful",
        "results": results
    }), 201


@app.route("/api/contribute/csv", methods=["POST"])
def contribute_csv():
    """Upload a CSV file with image paths and labels."""
    if "csv" not in request.files:
        return jsonify({"error": "No CSV file provided"}), 400
    
    file = request.files["csv"]
    contributor_id = validate_contributor_id(request.form.get("contributor_id", "anonymous"))
    image_base_dir = request.form.get("image_base_dir", "")
    
    if not allowed_file(file.filename, ALLOWED_DATA_EXTENSIONS):
        return jsonify({"error": "Only CSV files are allowed"}), 400
    
    try:
        df = pd.read_csv(file.stream)
    except Exception as e:
        return jsonify({"error": f"Could not parse CSV: {str(e)}"}), 400
    
    if "image_path" not in df.columns or "label" not in df.columns:
        return jsonify({
            "error": "CSV must have 'image_path' and 'label' columns",
            "found_columns": list(df.columns)
        }), 400
    
    results = {"added": 0, "skipped": 0, "errors": []}
    
    for idx, row in df.iterrows():
        label = sanitize_label(row["label"])
        if not label:
            results["skipped"] += 1
            continue
        
        img_path = str(row["image_path"])
        if image_base_dir:
            img_path = os.path.join(image_base_dir, img_path)
        
        if not os.path.exists(img_path):
            results["errors"].append(f"Row {idx}: file not found: {img_path}")
            results["skipped"] += 1
            continue
        
        # Validate image
        try:
            img = Image.open(img_path)
            img.verify()
        except Exception:
            results["errors"].append(f"Row {idx}: invalid image: {img_path}")
            results["skipped"] += 1
            continue
        
        # Copy image to our data store
        filename = f"{uuid.uuid4()}_{os.path.basename(img_path)}"
        label_dir = os.path.join(DATA_FOLDER, "images", secure_filename(label))
        os.makedirs(label_dir, exist_ok=True)
        dest_path = os.path.join(label_dir, filename)
        
        # Copy the file
        import shutil
        shutil.copy2(img_path, dest_path)
        
        data_store.add_contribution(
            contributor_id=contributor_id,
            image_path=dest_path,
            label=label
        )
        results["added"] += 1
    
    return jsonify({
        "message": f"Processed CSV: {results['added']} added, {results['skipped']} skipped",
        "details": results
    }), 201


@app.route("/api/train", methods=["POST"])
def train_model():
    """Trigger model training on accumulated data."""
    if pipeline.is_training:
        return jsonify({"error": "Training already in progress"}), 409
    
    verified_only = request.json.get("verified_only", False) if request.json else False
    epochs = request.json.get("epochs", EPOCHS) if request.json else EPOCHS
    fine_tune = request.json.get("fine_tune", False) if request.json else False
    
    # Cap epochs
    epochs = min(max(1, int(epochs)), 100)
    
    contributions = data_store.get_training_data(verified_only=verified_only)
    
    if len(contributions) < 10:
        return jsonify({
            "error": "Not enough training data. Need at least 10 samples.",
            "current_samples": len(contributions)
        }), 400
    
    # Check class distribution
    class_counts = {}
    for c in contributions:
        class_counts[c["label"]] = class_counts.get(c["label"], 0) + 1
    
    if len(class_counts) < 2:
        return jsonify({
            "error": "Need at least 2 different classes",
            "current_classes": list(class_counts.keys())
        }), 400
    
    # Start training in background thread
    def train_async():
        result = pipeline.train(contributions, epochs=epochs, fine_tune=fine_tune)
        logger.info(f"Async training result: {result}")
    
    training_thread = threading.Thread(target=train_async, daemon=True)
    training_thread.start()
    
    return jsonify({
        "message": "Training started",
        "num_samples": len(contributions),
        "class_distribution": class_counts,
        "epochs": epochs,
        "fine_tune": fine_tune,
        "verified_only": verified_only
    }), 202


@app.route("/api/train/sync", methods=["POST"])
def train_model_sync():
    """Trigger model training synchronously (waits for completion)."""
    if pipeline.is_training:
        return jsonify({"error": "Training already in progress"}), 409
    
    verified_only = request.json.get("verified_only", False) if request.json else False
    epochs = request.json.get("epochs", EPOCHS) if request.json else EPOCHS
    fine_tune = request.json.get("fine_tune", False) if request.json else False
    
    epochs = min(max(1, int(epochs)), 100)
    
    contributions = data_store.get_training_data(verified_only=verified_only)
    
    if len(contributions) < 10:
        return jsonify({
            "error": "Not enough training data",
            "current_samples": len(contributions)
        }), 400
    
    class_counts = {}
    for c in contributions:
        class_counts[c["label"]] = class_counts.get(c["label"], 0) + 1
    
    if len(class_counts) < 2:
        return jsonify({
            "error": "Need at least 2 different classes",
            "current_classes": list(class_counts.keys())
        }), 400
    
    result = pipeline.train(contributions, epochs=epochs, fine_tune=fine_tune)
    
    if "error" in result:
        return jsonify(result), 500
    
    return jsonify(result), 200


@app.route("/api/predict", methods=["POST"])
def predict():
    """Predict the class of an uploaded image."""
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    file = request.files["image"]
    
    if not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": "Invalid file type"}), 400
    
    # Validate image
    try:
        img = Image.open(file.stream)
        img.verify()
        file.stream.seek(0)
    except Exception:
        return jsonify({"error": "Invalid image file"}), 400
    
    # Save temporarily
    temp_path = os.path.join(UPLOAD_FOLDER, f"pred_{uuid.uuid4()}.png")
    file.save(temp_path)
    
    try:
        result = pipeline.predict(temp_path)
        return jsonify(result)
    finally:
        # Clean up temp file
        if os.path.exists(temp_path):
            os.remove(temp_path)


@app.route("/api/predict/and/contribute", methods=["POST"])
def predict_and_contribute():
    """Predict and optionally contribute the image with the correct label."""
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    file = request.files["image"]
    correct_label = request.form.get("correct_label", "").strip()
    contributor_id = validate_contributor_id(request.form.get("contributor_id", "anonymous"))
    
    if not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": "Invalid file type"}), 400
    
    # Validate image
    try:
        img = Image.open(file.stream)
        img.verify()
        file.stream.seek(0)
    except Exception:
        return jsonify({"error": "Invalid image file"}), 400
    
    # Save
    filename = f"{uuid.uuid4()}_{secure_filename(file.filename)}"
    temp_path = os.path.join(UPLOAD_FOLDER, filename)
    file.save(temp_path)
    
    # Predict
    prediction = pipeline.predict(temp_path)
    
    response = {"prediction": prediction}
    
    # If user provides a correct label, contribute it
    if correct_label:
        correct_label = sanitize_label(correct_label)
        if correct_label:
            label_dir = os.path.join(DATA_FOLDER, "images", secure_filename(correct_label))
            os.makedirs(label_dir, exist_ok=True)
            dest_path = os.path.join(label_dir, filename)
            
            import shutil
            shutil.move(temp_path, dest_path)
            
            contribution_id = data_store.add_contribution(
                contributor_id=contributor_id,
                image_path=dest_path,
                label=correct_label,
                confidence=prediction.get("top_confidence") if isinstance(prediction, dict) else None
            )
            
            response["contribution"] = {
                "contribution_id": contribution_id,
                "label": correct_label
            }
        else:
            os.remove(temp_path)
    else:
        # Clean up
        if os.path.exists(temp_path):
            os.remove(temp_path)
    
    return jsonify(response)


@app.route("/api/contributions", methods=["GET"])
def list_contributions():
    """List recent contributions."""
    page = request.args.get("page", 1, type=int)
    per_page = request.args.get("per_page", 50, type=int)
    per_page = min(per_page, 200)
    
    contributions = data_store.get_training_data()
    
    # Sort by newest first
    contributions.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    
    start = (page - 1) * per_page
    end = start + per_page
    
    page_data = contributions[start:end]
    
    # Remove file paths from response for security
    safe_data = []
    for c in page_data:
        safe_data.append({
            "id": c["id"],
            "contributor_id": c["contributor_id"],
            "label": c["label"],
            "verified": c["verified"],
            "flagged": c["flagged"],
            "timestamp": c["timestamp"]
        })
    
    return jsonify({
        "contributions": safe_data,
        "total": len(contributions),
        "page": page,
        "per_page": per_page,
        "total_pages": (len(contributions) + per_page - 1) // per_page
    })


@app.route("/api/contributions/<contribution_id>/flag", methods=["POST"])
def flag_contribution(contribution_id):
    """Flag a contribution as potentially incorrect."""
    reason = request.json.get("reason", "") if request.json else ""
    
    success = data_store.flag_contribution(contribution_id, reason)
    if success:
        return jsonify({"message": "Contribution flagged"})
    return jsonify({"error": "Contribution not found"}), 404


@app.route("/api/contributions/<contribution_id>/verify", methods=["POST"])
def verify_contribution(contribution_id):
    """Verify a contribution as correct."""
    success = data_store.verify_contribution(contribution_id)
    if success:
        return jsonify({"message": "Contribution verified"})
    return jsonify({"error": "Contribution not found"}), 404


@app.route("/api/stats", methods=["GET"])
def get_stats():
    """Get overall statistics."""
    data_stats = data_store.get_stats()
    model_info = pipeline.get_model_info()
    
    return jsonify({
        "data": data_stats,
        "model": model_info,
        "timestamp": datetime.now().isoformat()
    })


@app.route("/api/training/history", methods=["GET"])
def training_history():
    """Get training history."""
    return jsonify({
        "history": pipeline.training_history
    })


@app.route("/api/leaderboard", methods=["GET"])
def contributor_leaderboard():
    """Get top contributors."""
    contributors = data_store.metadata.get("contributors", {})
    
    leaderboard = []
    for cid, info in contributors.items():
        leaderboard.append({
            "contributor_id": cid,
            "total_contributions": info["total_contributions"],
            "verified_contributions": info["verified_contributions"],
            "first_contribution": info["first_contribution"]
        })
    
    leaderboard.sort(key=lambda x: x["verified_contributions"], reverse=True)
    
    return jsonify({
        "leaderboard": leaderboard[:100],
        "total_contributors": len(leaderboard)
    })


